//! `GlobalAlloc` wrappers that track peak simultaneous allocation.
//!
//! Sit on top of `embedded-alloc` heaps. Two relaxed atomic ops per
//! alloc / dealloc, negligible next to the work the crypto libraries
//! do inside.
//!
//! The wrapper is generated by macro for each underlying heap type so
//! each concrete wrapper keeps a `const fn empty()` suitable for
//! `#[global_allocator]`; a generic `TrackingHeap<H>` would need a
//! separate `HeapInit` trait with const-fn methods, which the crates
//! don't expose.

use core::alloc::{GlobalAlloc, Layout};
use core::sync::atomic::{AtomicUsize, Ordering};

macro_rules! define_tracking_heap {
    ($name:ident, $inner:path, $doc:literal) => {
        #[doc = $doc]
        pub struct $name {
            inner: $inner,
            current: AtomicUsize,
            peak: AtomicUsize,
        }

        impl $name {
            /// Construct an uninitialised wrapper. Callable in a const
            /// context so it can back a `#[global_allocator]` static.
            #[must_use]
            pub const fn empty() -> Self {
                Self {
                    inner: <$inner>::empty(),
                    current: AtomicUsize::new(0),
                    peak: AtomicUsize::new(0),
                }
            }

            /// Initialise the backing heap with the given SRAM region.
            ///
            /// # Safety
            ///
            /// Same contract as the underlying heap's `init`: call
            /// exactly once, before any allocation, with a
            /// unique `[start, start + size)` region owned by the heap
            /// for the remainder of the program.
            pub unsafe fn init(&self, start: usize, size: usize) {
                // SAFETY: delegated under the same contract as this fn.
                unsafe { self.inner.init(start, size) }
            }

            /// Peak bytes allocated simultaneously since the last
            /// [`reset_peak`](Self::reset_peak).
            pub fn peak(&self) -> usize {
                self.peak.load(Ordering::Relaxed)
            }

            /// Bytes currently allocated.
            pub fn current(&self) -> usize {
                self.current.load(Ordering::Relaxed)
            }

            /// Rewind `peak` to `current`. Typical usage: call right
            /// before the measured operation so the readout captures
            /// only that operation's peak.
            pub fn reset_peak(&self) {
                self.peak
                    .store(self.current.load(Ordering::Relaxed), Ordering::Relaxed);
            }
        }

        // SAFETY: all memory operations are delegated to the inner
        // heap under the `GlobalAlloc` contract; the atomic bookkeeping
        // introduces no aliasing or ownership changes.
        unsafe impl GlobalAlloc for $name {
            unsafe fn alloc(&self, layout: Layout) -> *mut u8 {
                // SAFETY: delegated.
                let ptr = unsafe { self.inner.alloc(layout) };
                if !ptr.is_null() {
                    let new = self.current.fetch_add(layout.size(), Ordering::Relaxed)
                        + layout.size();
                    self.peak.fetch_max(new, Ordering::Relaxed);
                }
                ptr
            }

            unsafe fn dealloc(&self, ptr: *mut u8, layout: Layout) {
                // SAFETY: delegated.
                unsafe { self.inner.dealloc(ptr, layout) }
                self.current.fetch_sub(layout.size(), Ordering::Relaxed);
            }
        }
    };
}

define_tracking_heap!(
    TrackingLlff,
    embedded_alloc::LlffHeap,
    "Peak-tracking wrapper around `embedded_alloc::LlffHeap` (linked-list first-fit)."
);
define_tracking_heap!(
    TrackingTlsf,
    embedded_alloc::TlsfHeap,
    "Peak-tracking wrapper around `embedded_alloc::TlsfHeap` (two-level segregated fit)."
);
